double calculatePower(double base, long long exp) {
    if (exp == 0) return 1.0;

    long long e = exp;
    if (e < 0) {
        base = 1.0 / base;
        e = -e;
    }

    double result = 1.0;
    while (e > 0) {
        if (e & 1) result *= base;
        base *= base;
        e >>= 1;
    }
    return result;
}

